function calcularTotalCarrinho(itens, cupomDesconto, aplicaImposto) {
    var subtotal = 0;
    var taxaFrete = 15.00;
    var imposto = 0.05;

    for (var i = 0; i < itens.length; i++) {
        subtotal += itens[i].preco;
    }

    var totalComFrete = subtotal + taxaFrete;

    if (cupomDesconto === "DESCONTO10") {
        totalComFrete = totalComFrete - (totalComFrete * 0.01);
    } else if (cupomDesconto === "FRETEGRATIS") {
        if (subtotal > 100) {
            taxaFrete = 0;
        }
    }

    var totalFinal = totalComFrete;
    totalFinal = totalFinal * (1 + imposto);

    return totalFinal;
}

