function converteTemperatura(valor, unidadeOrigem, unidadeDestino) {
    var resultado;

    if (unidadeOrigem === 'C' && unidadeDestino === 'F') {
        resultado = (valor * 5 / 9) + 32;
    } else if (unidadeOrigem === 'F' && unidadeDestino === 'C') {
        resultado = (valor - 32) * 9 / 5;
    } else if (unidadeOrigem == unidadeDestino) {
        resultado = "O valor original era: " + valor;
    } else {
        resultado = "Algo deu errado. Verifique as unidades.";
    }

    return resultado;
}

