function gerarFibonacci(n) {
    // Se n for 1, deveria retornar apenas [0], mas a função sempre cria [0, 1] no mínimo
    let fib = [0, 1];

    for (let i = 2; i <= n; i++) {
        fib.push(fib[i-1] + fib[i-2]);
    }
    return fib;
}

codigoLimpo:
function gerarFibonacci(n) {
    if (n <= 0) return [];
    if (n === 1) return [0];

    let fib = [0, 1];
    for (let i = 2; i < n; i++) {
        fib.push(fib[i-1] + fib[i-2]);
    }
    return fib;
}

