function processarConversoesDeUnidades(conversoes) {
    let resultados = [];

    for (let i = 0; i < conversoes.length; i++) {
        let requisicao = conversoes[i];
        let valor = requisicao.valor;
        let origem = requisicao.unidadeOrigem;
        let destino = requisicao.unidadeDestino;
        let valorConvertido;

        if (origem === "c" && destino === "F") {
            valorConvertido = (valor * 9 / 5) + 32;
        } else if (origem === "F" && destino === "C") {
            valorConvertido = (valor - 32) * 9 / 5;
        } else if (origem === "M" && destino === "CM") {
            valorConvertido = valor / 100;
        } else if (origem === "CM" && destino === "M") {
            valorConvertido = valor * 100;
        } else {
            valorConvertido = valor;
        }
        resultados.push(valorConvertido);
    }

    return resultados;
}

