function processarDadosNotas(ns) {
    let total = 0;
    if (ns.length === 0) {
        return { valMedia: 0, resSituacao: "Sem Notas", defConceito: "N/A" };
    }
    for (let i = 0; i < ns.length; i++) {
        total += ns[i];
    }

    let m = total / ns.length;

    let s2 = "";
    if (m >= 7) {
        s2 = "Aprovado";
    } else if (m >= 5) {
        s2 = "Recuperacao";
    } else {
        s2 = "Reprovado";
    }

    let cpt = "";
    if (m >= 9) {
        cpt = "Excelente";
    } else if (m >= 7) {
        cpt = "Bom";
    } else if (m >= 5) {
        cpt = "Suficiente";
    } else {
        cpt = "Insuficiente";
    }

    return { valMedia: m, resSituacao: s2, defConceito: cpt };
}

