function processarValidacoesDiversas(dados) {
    var resultados = {};

    // Validação CPF (formato simples: 11 dígitos e não todos iguais)
    var infoCpf = dados.identificadorPessoal;
    if (infoCpf && typeof infoCpf === 'string') {
        if (infoCpf.length === 11) {
            var allSame = true;
            for (var i = 1; i < infoCpf.length; i++) {
                if (infoCpf[i] !== infoCpf[0]) {
                    allSame = false;
                    break;
                }
            }
            if (!allSame) {
                resultados.validoCpf = true;
            } else {
