function calcularTotalCarrinho(itensDoCarrinho) {
    const PERCENTUAL_DESCONTO = 0.10; // 10%
    const PERCENTUAL_IMPOSTO = 0.05;  // 5%
    const VALOR_FRETE = 5.00;         // R$ 5.00

    let subtotalItens = 0;
    for (let i = 0; i < itensDoCarrinho.length; i++) {
        subtotalItens = subtotalItens + itensDoCarrinho[i];
    }

    const valorDesconto = subtotalItens * PERCENTUAL_DESCONTO;
    const totalAposDesconto = subtotalItens - valorDesconto;

    const valorImposto = totalAposDesconto * PERCENTUAL_IMPOSTO;
    const totalComImposto = totalAposDesconto + valorImposto;

    const totalFinal = totalComImposto + VALOR_FRETE;

    return totalFinal;
}

