function calculaValorEstranho(param) {
    if (param === 0) {
        return 0;
    }
    if (param === 1) {
        return 1;
    }

    let a = 0;
    let b = 1;
    let c = 0;

    for (let x = 2; x <= param; x++) {
        c = a + b;
        a = b;
        b = c;
    }

    return c;
}

